// ===== 수집 설정 =====
// OBF 카테고리 + Gemini 보충 카테고리 맵핑
const cats = [
  {obf:'face-creams', gem:'face cream moisturizer', kr:'수분크림/페이스크림'},
  {obf:'sunscreens', gem:'sunscreen SPF', kr:'선크림'},
  {obf:'shampoos', gem:'shampoo', kr:'샴푸'},
  {obf:'cleansers', gem:'facial cleanser', kr:'클렌저'},
  {obf:'body-milks', gem:'body lotion milk', kr:'바디로션'},
  {obf:'toners', gem:'toner skin', kr:'토너/스킨'},
  {obf:'lip-balms', gem:'lip balm lipstick', kr:'립밤/립스틱'},
  {obf:'foundations', gem:'foundation BB cream', kr:'파운데이션'},
  {obf:'eye-creams', gem:'eye cream', kr:'아이크림'},
  {obf:'face-masks', gem:'sheet mask face mask', kr:'마스크팩'},
  {obf:'hair-conditioners', gem:'conditioner treatment', kr:'컨디셔너'}
];
const regions = ['korea','japan','usa','europe','china'];
const catIdx = Math.floor(Date.now()/10800000) % cats.length;
const regIdx = Math.floor(Date.now()/32400000) % regions.length;
const cat = cats[catIdx];

return [{
  json: {
    obf_category: cat.obf,
    gemini_category: cat.gem,
    kr_name: cat.kr,
    region: regions[regIdx],
    batch_size: 10,
    run_id: 'prod_' + Date.now(),
    timestamp: new Date().toISOString()
  }
}];

// ===== OBF 응답 파싱 =====
// 전성분이 있는 제품만 필터링
const data = $input.first().json;
const products = (data.products || []).filter(p => (p.ingredients_text || '').length > 20);

if (products.length === 0) {
  return [{ json: { source: 'obf', count: 0, no_data: true } }];
}

return products.map(p => ({
  json: {
    brand_name: (p.brands || '').split(',')[0].trim(),
    product_name: (p.product_name || '').trim(),
    product_name_local: '',
    full_ingredients: (p.ingredients_text || '').trim(),
    key_ingredients: '',
    product_type: '',
    target_skin_type: 'all',
    ph_range: '',
    viscosity_type: '',
    country_of_origin: (p.countries_tags || []).join(', '),
    retail_price_usd: null,
    volume_ml: p.quantity || '',
    image_url: (p.image_url || '').trim(),
    brand_website: '',
    notable_claims: '',
    launch_year: null,
    category: (p.categories || '').trim(),
    source: 'open_beauty_facts',
    collected_at: new Date().toISOString()
  }
}));

// ===== Gemini 응답 파싱 =====
const input = $input.first().json;
let products = [];

try {
  const text = input.candidates?.[0]?.content?.parts?.[0]?.text || '[]';
  const cleaned = text.replace(/```json\n?|```\n?/g, '').trim();
  products = JSON.parse(cleaned);
  if (!Array.isArray(products)) products = [products];
} catch(e) {
  return [{ json: { error: 'gemini_parse_failed', message: e.message } }];
}

return products.filter(p => p.brand_name && p.product_name).map(p => ({
  json: {
    brand_name: (p.brand_name || '').trim(),
    product_name: (p.product_name || '').trim(),
    product_name_local: (p.product_name_local || '').trim(),
    full_ingredients: (p.full_ingredients || '').trim(),
    key_ingredients: JSON.stringify(p.key_ingredients || []),
    product_type: (p.product_type || '').trim(),
    target_skin_type: (p.target_skin_type || 'all').trim(),
    ph_range: (p.pH_range || p.ph_range || '').trim(),
    viscosity_type: (p.viscosity_type || '').trim(),
    country_of_origin: (p.country_of_origin || '').trim(),
    retail_price_usd: parseFloat(p.retail_price_usd) || null,
    volume_ml: parseFloat(p.volume_ml) || null,
    image_url: (p.image_url || '').trim(),
    brand_website: (p.brand_website || '').trim(),
    notable_claims: (p.notable_claims || '').trim(),
    launch_year: parseInt(p.launch_year) || null,
    category: '',
    source: 'gemini_search',
    collected_at: new Date().toISOString()
  }
}));

// ===== OBF + Gemini 데이터 통합 및 중복 제거 =====
const obfItems = $('🔄 OBF 파싱').all().map(i => i.json).filter(i => !i.no_data);
const geminiItems = $('🔄 Gemini 파싱').all().map(i => i.json).filter(i => !i.error);
const all = [...obfItems, ...geminiItems];

// 중복 제거 (brand+product 기준)
const seen = new Set();
const unique = all.filter(p => {
  const key = ((p.brand_name||'') + (p.product_name||'')).toLowerCase().replace(/\s+/g, '');
  if (seen.has(key) || !p.product_name) return false;
  seen.add(key);
  return true;
});

console.log(`통합 결과: OBF ${obfItems.length}건 + Gemini ${geminiItems.length}건 = 중복제거 후 ${unique.length}건`);
return unique.map(p => ({ json: p }));

// ===== 물성 분석 Gemini 요청 구성 =====
const items = $input.all();
if (!items.length || !items[0].json.id) {
  return [{ json: { skip: true, reason: 'no_candidates' } }];
}

const products = items.map(i => ({
  id: i.json.id,
  name: i.json.brand_name + ' ' + i.json.product_name,
  ingredients: (i.json.full_ingredients || '').substring(0, 500)
}));

const prompt = `You are a cosmetic formulation scientist. Estimate physical properties for these products based on their ingredient lists.

Products:
${JSON.stringify(products, null, 2)}

For EACH product estimate:
1. ph_value: Estimated pH (number, e.g. 5.5)
2. viscosity_cp: Estimated viscosity in centipoise (number)
3. specific_gravity: Estimated specific gravity (number)
4. appearance: Visual description
5. texture: Texture description
6. shelf_life_months: Estimated shelf life in months (number)

Be scientific and realistic. Respond as JSON array with product id included. No explanation.`;

return [{ json: { prompt } }];

// ===== 물성 응답 파싱 =====
const input = $input.first().json;
if (input.skip) return [{ json: { skip: true } }];

let results = [];
try {
  const text = input.candidates?.[0]?.content?.parts?.[0]?.text || '[]';
  results = JSON.parse(text.replace(/```json\n?|```\n?/g, '').trim());
  if (!Array.isArray(results)) results = [results];
} catch(e) {
  return [{ json: { error: 'property_parse_failed', message: e.message } }];
}

return results.map(r => ({
  json: {
    product_id: r.id || r.product_id,
    ph_value: parseFloat(r.ph_value) || null,
    viscosity_cp: parseFloat(r.viscosity_cp) || null,
    specific_gravity: parseFloat(r.specific_gravity) || null,
    appearance: (r.appearance || '').trim(),
    texture: (r.texture || '').trim(),
    shelf_life_months: parseInt(r.shelf_life_months) || null
  }
}));

// ===== Claude 분석 준비 =====
const timestamp = new Date().toISOString();
const prompt = '최근 수집된 화장품 제품 전성분 검증 및 가이드처방 DB 연계 분석을 JSON으로 요약해줘.';

return [{
  json: {
    command: "cd /home/kpros && echo '" + prompt.replace(/'/g, "'\\'") + "' | /home/kpros/.npm-global/bin/claude -p --output-format json 2>/dev/null | head -c 5000",
    timestamp
  }
}];

// ===== 실행 리포트 =====
const input = $input.first().json;
let analysis = {};
try {
  analysis = JSON.parse(input.stdout || '{}');
} catch(e) {
  analysis = { raw_output: (input.stdout || '').substring(0, 2000) };
}

return [{
  json: {
    report: '✅ 제품 수집 완료 (OBF + Gemini 혼합)',
    claude_analysis: analysis,
    timestamp: new Date().toISOString(),
    next_run: new Date(Date.now() + 3*60*60*1000).toISOString()
  }
}];
